#!/usr/bin/env bash\nset -euo pipefail\n\n# Deploy/start script for the backend (Node.js)\n# Safe defaults:\n# - Uses npm by default; set PACKAGE_MANAGER to npm|yarn|pnpm\n# - Runs build step if package.json defines it\n# - Starts via `npm start` (or yarn/pnpm equivalent)\n# - Respects PORT and NODE_ENV if provided\n\nROOT_DIR="$(cd ""){BASH_SOURCE[0]}" && pwd)"\ncd "$ROOT_DIR"\n\nPACKAGE_MANAGER="
${PACKAGE_MANAGER:-npm}"\nNODE_ENV="
${NODE_ENV:-production}"\nexport NODE_ENV\n\n# Prefer locally installed node_modules/.bin in PATH\nexport PATH="$ROOT_DIR/node_modules/.bin:$PATH"\n\nrun_pm() {\n  case "$PACKAGE_MANAGER" in\n    npm)\n      npm "$@"\n      ;;\n    yarn)\n      yarn "$@"\n      ;;\n    pnpm)\n      pnpm "$@"\n      ;;\n    *)\n      echo "Unsupported PACKAGE_MANAGER: $PACKAGE_MANAGER (use npm|yarn|pnpm)" >&2\n      exit 2\n      ;;\n  esac\n}\n\nif [[ ! -f package.json ]]; then\n  echo "package.json not found at repo root ($ROOT_DIR). If your backend lives in a subdir, run from there or adjust script." >&2\n  exit 1\nfi\n\necho "Using PACKAGE_MANAGER=$PACKAGE_MANAGER"\n\necho "Installing dependencies..."\ncase "$PACKAGE_MANAGER" in\n  npm)\n    if [[ -f package-lock.json ]]; then\n      npm ci\n    else\n      npm install\n    fi\n    ;;\n  yarn)\n    if [[ -f yarn.lock ]]; then\n      yarn install --frozen-lockfile\n    else\n      yarn install\n    fi\n    ;;\n  pnpm)\n    pnpm install --frozen-lockfile\n    ;;\n esac\n\n# If a build script exists, run it\nif node -e "const p=require('./package.json');process.exit(p.scripts&&p.scripts.build?0:1)"; then\n  echo "Running build..."\n  run_pm run build\nelse\n  echo "No build script found; skipping build."\nfi\n\n# If a migrate script exists, run it\nif node -e "const p=require('./package.json');process.exit(p.scripts&&p.scripts.migrate?0:1)"; then\n  echo "Running migrations..."\n  run_pm run migrate\nelse\n  echo "No migrate script found; skipping migrations."\nfi\n\necho "Starting server (NODE_ENV=$NODE_ENV, PORT=${PORT:-<unset>})..."\n# Use `start` script (must be defined in package.json)\nrun_pm run start\n